require "common.ui.window.GUICustomShopSubTab"

GUICustomShopTab = class("GUICustomShopTab", IGUIWindow)

function GUICustomShopTab:onLoad()
    self.cbTab = self:getChildWindowByName("BedWarCustomShopTab-Tab", GUIType.CheckBox)
    self.ivIcon = self:getChildWindowByName("BedWarCustomShopTab-Icon", GUIType.StaticImage)
    self.tvName = self:getChildWindowByName("BedWarCustomShopTab-Name", GUIType.StaticText)
    self.llTabs = self:getChildWindowByName("BedWarCustomShopTab-SubTabs", GUIType.Layout)
    self.tabs = {}
    self.cbTab:registerEvent(GUIEvent.CheckStateChanged, function()
        if self.cbTab:GetChecked() then
            self.cbTab:SetTouchable(#self.tabs > 0)
            self.llTabs:SetVisible(true)
            if #self.tabs > 0 then
                self.root:SetArea({ 0, 0 }, self.root:GetYPosition(), { 1, 0 }, { 0, self.contentHeight + self.closeHeight })
                self.tabs[1]:setChecked(true)
            end
            GUICustomShop:onSelectTab(self)
        else
            self.llTabs:SetVisible(false)
            if #self.tabs > 0 then
                self.root:SetArea({ 0, 0 }, self.root:GetYPosition(), { 1, 0 }, { 0, self.closeHeight })
            end
        end
        GUICustomShop:updateTabsLayout(self)
    end)

    self.cbTab:registerEvent(GUIEvent.Click, function()
        SoundUtil.playSound(SoundConfig.selectTabStore)
    end)
end

function GUICustomShopTab:onDataChanged(tabs)
    self.type = tabs[1].Type
    self.tabId = tabs[1].TabId
    if #tabs == 1 then
        self.cbTab:SetNormalImage("set:bed_war_store.json image:tab_nor")
        self.cbTab:SetPushedImage("set:bed_war_store.json image:tab_pre")
    else
        self.cbTab:SetNormalImage("set:bed_war_custom_shop.json image:tab2_nor_arrow")
        self.cbTab:SetPushedImage("set:bed_war_custom_shop.json image:tab2_pre_arrow")
        self:initTabs(tabs)
    end
    self.ivIcon:SetImage(tabs[1].Icon)
    self.tvName:SetText(Lang:getString(tabs[1].TypeLang))
end

function GUICustomShopTab:initTabs(tabs)
    self.closeHeight = self.root:GetPixelSize().y
    self.contentHeight = 57 * #tabs
    self.llTabs:SetArea({ 0, 0 }, { 0, self.closeHeight }, { 1, 0 }, { 0, self.contentHeight })
    self.llTabs:SetVisible(false)
    local startY = 6
    for _, _tab in pairs(tabs) do
        local tab = GUICustomShopSubTab.new("BedWarCustomShopSubTab.json")
        tab.root:registerEvent(GUIEvent.CheckStateChanged, function()
            if tab.cbTab:GetChecked() then
                tab.root:SetTouchable(false)
                self:onSelectSubTab(tab)
            end
            tab.tvName:SetBordered(tab.cbTab:GetChecked())
        end)
        tab:setArea({ 0, 9 }, { 0, startY }, { 1, -18 }, { 0, 45 })
        tab:onDataChanged(_tab)
        self.llTabs:AddChildWindow(tab.root)
        table.insert(self.tabs, tab)
        startY = startY + 57
    end
end

function GUICustomShopTab:setChecked(check)
    self.cbTab:SetChecked(check)
    self.cbTab:SetTouchable(not check)
    if #self.tabs == 0 then
        return
    end
    self.cbTab:SetTouchable(true)
    if GUICustomShop.curSelectTab and GUICustomShop.curSelectTab.tabId == self.tabId then
        self.cbTab:SetNormalImage("set:bed_war_custom_shop.json image:tab2_pre_arrow_select")
    else
        self.cbTab:SetNormalImage("set:bed_war_custom_shop.json image:tab2_nor_arrow")
    end
end

function GUICustomShopTab:onSelectSubTab(tab)
    for _, _tab in pairs(self.tabs) do
        _tab:setChecked(_tab.tabId == tab.tabId)
    end
    GUICustomShop:onSelectSubTab(tab)
end